import { buildSectionPage } from '../../utils/section-page.utils.js';
import {
    AppTimeZoneService,
    appTimeZoneService as defaultService,
} from '../../services/app-timezone.service.js';
import type { ScreenComponent } from '../../types/screen-component.js';
import { createComponentLogger } from '../../utils/component-logger.js';

const template = document.createElement('template');
template.innerHTML = `
    <section class="timezone-settings">
        <p class="timezone-settings__effective">
            Effective timezone: <strong data-testid="effective-zone"></strong>
        </p>
        <fieldset class="timezone-settings__mode">
            <legend>How should the app pick the timezone?</legend>
            <label>
                <input type="radio" name="tz-mode" value="device" data-testid="mode-device">
                <span>Follow this device (<span data-testid="device-zone"></span>)</span>
            </label>
            <label>
                <input type="radio" name="tz-mode" value="fixed" data-testid="mode-fixed">
                <span>Pin a fixed timezone</span>
            </label>
        </fieldset>
        <div class="timezone-settings__pin" data-testid="pin-row" hidden>
            <input list="tz-list" type="text" data-testid="zone-input" placeholder="e.g. Europe/Amsterdam">
            <datalist id="tz-list"></datalist>
        </div>
        <div class="timezone-settings__actions">
            <button type="button" data-testid="save">Save</button>
            <span class="timezone-settings__saved" data-testid="saved" hidden>Saved ✓</span>
        </div>
        <p class="timezone-settings__error" data-testid="error" hidden></p>
    </section>
`;

export class TimezoneSettingsScreen extends HTMLElement implements ScreenComponent {
    setLoading(): void {}
    setError(err: unknown): void { this.showError(err); }
    clearStatus(): void { this.clearError(); }

    private initialized = false;
    private readonly log = createComponentLogger('timezone-settings-screen');
    private service: AppTimeZoneService = defaultService;

    setService(service: AppTimeZoneService): void {
        this.service = service;
        if (this.initialized) void this.refresh();
    }

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Timezone', 'extra', '/settings/timezone');
        page.content.classList.add('timezone-settings-host');
        page.content.appendChild(template.content.cloneNode(true));

        this.populateZoneList();

        const deviceRadio = this.queryEl<HTMLInputElement>('mode-device');
        const fixedRadio = this.queryEl<HTMLInputElement>('mode-fixed');
        deviceRadio.addEventListener('change', () => this.syncPinRowVisibility());
        fixedRadio.addEventListener('change', () => this.syncPinRowVisibility());
        this.queryEl<HTMLButtonElement>('save').addEventListener('click', () => void this.handleSave());

        void this.refresh();
    }

    private populateZoneList(): void {
        const list = this.queryEl<HTMLDataListElement>('tz-list', 'id');
        // Native, dependency-free list of every IANA zone the runtime knows.
        const zones = typeof Intl.supportedValuesOf === 'function'
            ? Intl.supportedValuesOf('timeZone')
            : ['Europe/Amsterdam'];
        for (const zone of zones) {
            const option = document.createElement('option');
            option.value = zone;
            list.appendChild(option);
        }
    }

    async refresh(): Promise<void> {
        try {
            const mode = await this.service.getMode();
            const effective = this.service.getTimeZone();
            this.queryEl<HTMLElement>('effective-zone').textContent = effective;
            this.queryEl<HTMLElement>('device-zone').textContent = Temporal.Now.timeZoneId();
            this.queryEl<HTMLInputElement>('mode-device').checked = mode === 'device';
            this.queryEl<HTMLInputElement>('mode-fixed').checked = mode === 'fixed';
            if (mode === 'fixed') this.queryEl<HTMLInputElement>('zone-input').value = effective;
            this.syncPinRowVisibility();
        } catch (error) {
            this.log.error('refresh failed:', error);
            this.showError(error);
        }
    }

    private syncPinRowVisibility(): void {
        const fixed = this.queryEl<HTMLInputElement>('mode-fixed').checked;
        this.queryEl<HTMLElement>('pin-row').hidden = !fixed;
    }

    private async handleSave(): Promise<void> {
        this.clearError();
        try {
            if (this.queryEl<HTMLInputElement>('mode-fixed').checked) {
                const zone = this.queryEl<HTMLInputElement>('zone-input').value.trim();
                await this.service.pinZone(zone);
            } else {
                await this.service.followDevice();
            }
            await this.refresh();
            this.flashSaved();
        } catch (error) {
            this.log.error('save failed:', error);
            this.showError(error);
        }
    }

    private flashSaved(): void {
        const el = this.queryEl<HTMLElement>('saved');
        el.hidden = false;
    }

    private queryEl<T extends HTMLElement>(id: string, attr: 'testid' | 'id' = 'testid'): T {
        const selector = attr === 'id' ? `#${id}` : `[data-testid="${id}"]`;
        const el = this.querySelector<T>(selector);
        if (!el) throw new Error(`timezone-settings: missing ${selector}`);
        return el;
    }

    private showError(error: unknown): void {
        const el = this.querySelector<HTMLElement>('[data-testid="error"]');
        if (!el) throw error;
        el.hidden = false;
        el.textContent = error instanceof Error ? `${error.message}\n${error.stack ?? ''}` : String(error);
    }

    private clearError(): void {
        const el = this.querySelector<HTMLElement>('[data-testid="error"]');
        if (!el) return;
        el.hidden = true;
        el.textContent = '';
    }
}

if (!customElements.get('timezone-settings-screen')) {
    customElements.define('timezone-settings-screen', TimezoneSettingsScreen);
}
